var results = $.steps.searchWeb.response.results || [];
var sourceText = '';
var citations = [];
results.forEach(function(r, i) {
  sourceText += 'SOURCE ' + (i + 1) + ': ' + (r.title || '') + '\n';
  sourceText += 'URL: ' + (r.url || '') + '\n';
  sourceText += (r.text || '').slice(0, 2000) + '\n\n';
  citations.push({ num: i + 1, title: r.title || '', url: r.url || '' });
});
return { sourceText: sourceText, citations: citations, sourceCount: results.length };

var data = $.steps.compileSources.output;
var prompt = 'You are a knowledgeable research assistant. Answer the following question using the provided web sources. Always cite your sources.

';
prompt += 'QUESTION: ' + $.input.question + '

';
prompt += 'WEB SOURCES (' + data.sourceCount + '):
' + data.sourceText + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Provide a clear, comprehensive answer
';
prompt += '- Cite sources using [1], [2], etc.
';
prompt += '- Note if information conflicts across sources
';
prompt += '- Indicate confidence level
';
prompt += '- Suggest follow-up questions

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "answer": "Comprehensive answer with [1] citations",
';
prompt += '  "confidence": "High|Medium|Low",
';
prompt += '  "keyTakeaways": ["takeaway1"],
';
prompt += '  "followUpQuestions": ["question1"],
';
prompt += '  "sourcesUsed": [1, 2, 3]
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'Medium', keyTakeaways: [], followUpQuestions: [], sourcesUsed: [] }; }

var ai = $.steps.parseAI.output;
var citations = $.steps.compileSources.output.citations;
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Research Answer', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + $.input.question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Confidence:* ' + (ai.confidence || 'Medium') } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.answer || '').slice(0, 2800) } });
if (ai.keyTakeaways && ai.keyTakeaways.length > 0) {
  blocks.push({ type: 'divider' });
  var takeaways = '*Key Takeaways:*\n';
  ai.keyTakeaways.forEach(function(t, i) { takeaways += (i + 1) + '. ' + t + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: takeaways.slice(0, 1800) } });
}
if (citations.length > 0) {
  blocks.push({ type: 'divider' });
  var srcText = '*Sources:*\n';
  citations.forEach(function(c) { srcText += '[' + c.num + '] <' + c.url + '|' + c.title + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}
if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  var followUp = '*Follow-up Questions:*\n';
  ai.followUpQuestions.forEach(function(q) { followUp += '- ' + q + '\n'; });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: followUp.slice(0, 500) }] });
}
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Researched with Exa + Claude AI via One CLI' }] });
var fallback = 'Answer: ' + (ai.answer || '').slice(0, 200);
return { blocks: blocks, fallback: fallback };
